import{a2 as s,a3 as a,an as t}from"./index.e471c64d.js";const p={class:"md-blog m-auto text-left"},o=t(`<h1 id="hexo-%E5%8D%9A%E5%AE%A2%E5%A4%9C%E9%97%B4%E6%A8%A1%E5%BC%8F%E7%9A%84%E5%AE%9E%E7%8E%B0%E5%85%BC-git-%E5%B7%A5%E4%BD%9C%E6%B5%81%E7%AE%80%E4%BB%8B" tabindex="-1">Hexo \u535A\u5BA2\u591C\u95F4\u6A21\u5F0F\u7684\u5B9E\u73B0\u517C git \u5DE5\u4F5C\u6D41\u7B80\u4ECB</h1><p>\u672C\u7BC7\u535A\u5BA2\u5C06\u8BB0\u5F55 Hexo \u9ED8\u8BA4 landscape \u4E3B\u9898\u7684\u591C\u95F4\u6A21\u5F0F\u5B9E\u73B0\uFF0C\u4EE5\u53CA git \u5DE5\u4F5C\u6D41\u7684\u7B80\u5355\u4ECB\u7ECD\u3002</p><h2 id="%E5%9F%BA%E6%9C%AC%E6%80%9D%E8%B7%AF" tabindex="-1">\u57FA\u672C\u601D\u8DEF</h2><p>\u8981\u60F3\u5B9E\u73B0\u591C\u95F4\u6A21\u5F0F\uFF0C\u5C31\u610F\u5473\u7740\u5E94\u7528 CSS \u7684\u6539\u53D8\u3002\u8FD9\u91CC\u4F5C\u4E3A js \u7EC3\u4E60\uFF0C\u91C7\u7528\u7EAF\u524D\u7AEF\u7684\u65B9\u6CD5\u5B9E\u73B0\uFF1A\u5982\u679C\u5F53\u524D\u5F00\u542F\u4E86\u591C\u95F4\u6A21\u5F0F\uFF0C\u90A3\u4E48\u5C31\u5411\u6839\u7ED3\u70B9\uFF0C\u5373 html \u7ED3\u70B9\u589E\u52A0\u4E00\u4E2A\u7C7B <code>dark-theme</code>\uFF0C\u518D\u91CD\u5199\u6DF1\u8272\u6A21\u5F0F\u4F7F\u7528\u7684\u6837\u5F0F\u8868\uFF0C\u653E\u7F6E\u5728\u539F\u6709\u6837\u5F0F\u8868\u6700\u540E\u5373\u53EF\u3002</p><p>\u4E3A\u4E86\u5B9A\u4F4D\u5230\u6839\u7ED3\u70B9\uFF0C\u53EF\u4EE5\u91C7\u7528 <code>document.documentElement</code></p><p>\u4E3A\u4E86\u5411\u67D0\u4E00\u7ED3\u70B9\u589E\u52A0 / \u5220\u9664\u7C7B\uFF0C\u53EF\u4EE5\u91C7\u7528 <code>classList.toggle(&#39;dark-theme&#39;)</code>\uFF0Ctoggle \u672C\u610F\u4FBF\u662F\u5728\u4E24\u79CD\u72B6\u6001\u95F4\u5207\u6362\u3002</p><p>\u4E8E\u662F\u5408\u5E76\uFF0C\u5C31\u5F97\u5230\u4E86\u7B2C\u4E00\u7248\u7684 js \u4EE3\u7801\uFF1A</p><pre class="language-javascript"><code class="language-javascript"><span class="token keyword">function</span> <span class="token function">changeDarkTheme</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  document<span class="token punctuation">.</span>documentElement<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">toggle</span><span class="token punctuation">(</span><span class="token string">&quot;dark-theme&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><p>\u63A5\u4E0B\u6765\u987A\u5229\u6210\u7AE0\u7684\u5F00\u59CB\u5199\u754C\u9762\u4E0A\u7684\u6309\u94AE\u4EE5\u53CA\u591C\u95F4\u6A21\u5F0F\u5BF9\u5E94\u7684\u6837\u5F0F\u8868\uFF1A</p><p>\u5BF9\u5E94\u7684 CSS \u6587\u4EF6\u53EF\u4EE5\u5728\u7F51\u9875\u7684\u68C0\u67E5\u4E2D\u627E\u5230\uFF0C\u90FD\u5199\u5728\u4E00\u5757\uFF0C\u5F88\u65B9\u4FBF\u770B\uFF08</p><p>\u8FD9\u6837\u4E00\u6765\u5C31\u5B8C\u6210\u4E86\u591C\u95F4\u6A21\u5F0F\u7684\u521D\u7248\u3002</p><h2 id="%E5%88%A9%E7%94%A8-sessionstorage-%E8%AE%B0%E5%BF%86" tabindex="-1">\u5229\u7528 sessionStorage \u8BB0\u5FC6</h2><p>\u5728\u4E0A\u6587\u90A3\u6837\u7B80\u5355\u5B8C\u6210\u521D\u7248\u540E\uFF0C\u95EE\u9898\u5F88\u5FEB\u5C31\u4F1A\u51FA\u73B0\uFF1A\u5F53\u8FDB\u5165\u65B0\u7684\u9875\u9762\u65F6\uFF0C\u7F51\u7AD9\u65E0\u6CD5\u8BB0\u4F4F\u4E4B\u524D\u7684\u9009\u62E9\uFF0C\u8FD9\u5C31\u5BFC\u81F4\u60F3\u4F7F\u7528\u591C\u95F4\u6A21\u5F0F\u65F6\uFF0C\u6BCF\u6B21\u8FDB\u5165\u65B0\u7684\u7F51\u9875\u90FD\u9700\u8981\u91CD\u65B0\u8BBE\u7F6E\u591C\u95F4\u6A21\u5F0F\uFF0C\u5F88\u9EBB\u70E6\u3002\u8FD9\u6837\u770B\u6765\uFF0C\u6211\u4EEC\u9700\u8981\u80FD\u591F\u5168\u5C40\u8BB0\u4F4F\u7528\u6237\u7684\u9009\u62E9\u3002</p><p>\u5728 html5 \u4E2D\uFF0C\u63D0\u4F9B\u4E86\u4E24\u79CD\u7AD9\u70B9\u672C\u5730\u5B58\u50A8\u7684\u65B9\u5F0F\uFF0C\u5206\u522B\u662F sessionStorage \u548C localStorage\u3002\u5B83\u4EEC\u7684\u533A\u522B\u5728\u4E8E sessionStorage \u7684\u6570\u636E\u4EC5\u76F8\u5F53\u4E8E\u5728\u5F53\u524D\u7684\u6807\u7B7E\u9875\u4E2D\u751F\u6548\uFF0C\u5173\u95ED\u6807\u7B7E\u9875\u540E\u6570\u636E\u5373\u4E22\u5931\uFF0C\u800C localStorage \u5219\u4F1A\u5168\u5C40\u751F\u6548\uFF0C\u5373\u4F7F\u5173\u95ED\u6D4F\u89C8\u5668\u4E5F\u4F1A\u7EE7\u7EED\u5B58\u50A8\u3002</p><p>\u8FD9\u91CC\u91C7\u7528 sessionStorage \u5B9E\u73B0\uFF08\u56E0\u4E3A\u5E0C\u671B\u6BCF\u6B21\u5148\u8003\u8651\u7528\u6237\u662F\u5426\u5DF2\u7ECF\u6709\u7CFB\u7EDF\u8BBE\u7F6E\u4E0A\u7684\u504F\u597D\uFF08\u6DF1\u8272\u6A21\u5F0F\uFF09\uFF09</p><pre class="language-javascript"><code class="language-javascript"><span class="token keyword">function</span> <span class="token function">changeDarkTheme</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  document<span class="token punctuation">.</span>documentElement<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">toggle</span><span class="token punctuation">(</span><span class="token string">&quot;dark-theme&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>document<span class="token punctuation">.</span>documentElement<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span><span class="token string">&quot;dark-theme&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    sessionStorage<span class="token punctuation">.</span><span class="token function">setItem</span><span class="token punctuation">(</span><span class="token string">&quot;hexoTheme&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    sessionStorage<span class="token punctuation">.</span><span class="token function">setItem</span><span class="token punctuation">(</span><span class="token string">&quot;hexoTheme&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;0&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">if</span> <span class="token punctuation">(</span>sessionStorage<span class="token punctuation">.</span><span class="token function">getItem</span><span class="token punctuation">(</span><span class="token string">&quot;hexoTheme&quot;</span><span class="token punctuation">)</span> <span class="token operator">===</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">//\u7B2C\u4E00\u6B21\u8BBF\u95EE\u7F51\u7AD9\uFF0C\u8BD5\u56FE\u53C2\u8003\u7CFB\u7EDF\u8BBE\u5B9A</span>
  <span class="token keyword">const</span> prefersDarkScheme <span class="token operator">=</span> window<span class="token punctuation">.</span><span class="token function">matchMedia</span><span class="token punctuation">(</span><span class="token string">&quot;(prefers-color-scheme: dark)&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>prefersDarkScheme<span class="token punctuation">.</span>matches<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    sessionStorage<span class="token punctuation">.</span><span class="token function">setItem</span><span class="token punctuation">(</span><span class="token string">&quot;hexoTheme&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;1&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token function">changeDarkTheme</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    sessionStorage<span class="token punctuation">.</span><span class="token function">setItem</span><span class="token punctuation">(</span><span class="token string">&quot;hexoTheme&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;0&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> theme <span class="token operator">=</span> sessionStorage<span class="token punctuation">.</span><span class="token function">getItem</span><span class="token punctuation">(</span><span class="token string">&quot;hexoTheme&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>theme <span class="token operator">==</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token function">changeDarkTheme</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><p>\u6BCF\u6B21\u6253\u5F00\u7F51\u9875\u65F6\uFF0C\u901A\u8FC7\u68C0\u6D4B sessionStorage \u5224\u65AD\u662F\u5426\u9700\u8981\u5E94\u7528\u591C\u95F4\u6A21\u5F0F\u3002\u800C\u591C\u95F4\u6A21\u5F0F\u7684\u5207\u6362\u6309\u94AE\u4F5C\u7528\u5C31\u662F\u6DFB\u52A0 / \u5220\u9664 <code>dark-theme</code> \u7C7B\uFF0C\u5E76\u66F4\u6539 sessionStorage\u3002</p><p class="tip info"> \u6CE8\u610F\uFF1A\u8FD9\u4E2A js \u5E94\u8BE5\u653E\u5728 head \u4E2D\u52A0\u8F7D\uFF0C\u5982\u679C\u653E\u5728 footer \u540E\u52A0\u8F7D\u4F1A\u5BFC\u81F4\u6D45\u8272\u6837\u5F0F\u751F\u6548\u540E\u518D\u5E94\u7528\u6DF1\u8272\u6A21\u5F0F </p><h2 id="git-%E5%B7%A5%E4%BD%9C%E6%B5%81" tabindex="-1">git \u5DE5\u4F5C\u6D41</h2><p>\u672C\u6B21\u589E\u52A0\u591C\u95F4\u6A21\u5F0F\u6240\u8FDB\u884C\u7684\u4FEE\u6539\u90FD\u662F\u5728\u4FEE\u6539 Hexo \u4E3B\u9898\u57FA\u7840\u4E4B\u4E0A\u5B8C\u6210\u7684\u3002\u800C\u4E00\u4E2A\u4E3B\u9898\u4F1A\u5305\u542B\u5F88\u591A\u6587\u4EF6\uFF0C\u6709\u65F6\u5019\u5F88\u96BE\u8BB0\u4F4F\u81EA\u5DF1\u6240\u8FDB\u884C\u7684\u4FEE\u6539\uFF0C\u518D\u52A0\u4E0A\u4FEE\u6539\u4E00\u822C\u4F1A\u5F88\u591A\u5F88\u6742\uFF0C\u8FD9\u4E2A\u65F6\u5019\u5C31\u5207\u5B9E\u9700\u8981\u4E00\u4E2A\u597D\u7528\u7684\u7248\u672C\u63A7\u5236\u5DE5\u5177\u3002\u4E8E\u662F\u8FD9\u91CC\u91C7\u7528\u4E86 git\u3002</p><h3 id="git-%E5%AE%89%E8%A3%85%E5%8F%8A%E9%85%8D%E7%BD%AE" tabindex="-1">git \u5B89\u88C5\u53CA\u914D\u7F6E</h3><p>git \u7684\u5B89\u88C5\u76F4\u63A5\u5728\u5B98\u7F51\u4E0B\u8F7D\u5373\u53EF\u3002Ubuntu \u5219\u53EF\u4EE5\u76F4\u63A5 <code>sudo apt-get install git</code> \u6765\u5B89\u88C5 git\u3002</p><p>\u6B64\u540E\u914D\u7F6E\u7528\u6237\u540D\u548C\u90AE\u7BB1\uFF1A</p><pre class="language-bash"><code class="language-bash"><span class="token function">git</span> config --global user.name <span class="token string">&quot;xxx&quot;</span>
<span class="token function">git</span> config --global user.email <span class="token string">&quot;xxx&quot;</span>
</code></pre><p>\u4E3A\u4E86\u642D\u914D GitHub \u4F7F\u7528\uFF0C\u53EF\u4EE5\u5229\u7528 SSH \u9A8C\u8BC1\u3002</p><p>\u8F93\u5165\uFF1A</p><pre class="language-bash"><code class="language-bash">ssh-keygen -C <span class="token string">&#39;you email address@gmail.com&#39;</span> -t rsa
</code></pre><p>\u5728 <code>~/.ssh</code> \u4E2D\u627E\u5230\u516C\u94A5\u6587\u4EF6\uFF0C\u6253\u5F00\u590D\u5236\u81F3\u81EA\u5DF1 GitHub \u8BBE\u7F6E\u4E2D\u53BB\u5373\u53EF\u3002</p><p>\u53EF\u4EE5\u901A\u8FC7 <code>git init</code> \u521D\u59CB\u5316\u4ED3\u5E93\uFF0C\u8003\u8651\u548C GitHub \u540C\u6B65\uFF0C\u5219\u53EF\u4EE5 <code>git clone</code> \u6765\u590D\u5236\u5DF2\u6709\u4ED3\u5E93\u3002GitHub \u67D0\u4E00\u4E2A\u4ED3\u5E93\u4E2D\u70B9\u51FB clone\uFF0C\u9009\u62E9 SSH\uFF0C\u590D\u5236\u540E\u9762\u5185\u5BB9\uFF0C\u6DFB\u52A0\u5230 <code>git clone</code> \u540E\u5373\u53EF\u3002\u4E5F\u53EF\u4EE5\u81EA\u884C\u6307\u5B9A\u672C\u5730\u4ED3\u5E93\u7684\u8DEF\u5F84\uFF0C\u5426\u5219\u5219\u4F1A clone \u5230\u5F53\u524D\u6587\u4EF6\u5939\u3002</p><p>\u6B64\u540E\u901A\u8FC7 <code>git commit -m &quot;\u8FD9\u91CC\u5199\u6CE8\u91CA&quot;</code> \u53EF\u4EE5\u63D0\u4EA4\u5F53\u524D\u4FEE\u6539\uFF08\u8FD8\u662F\u5728\u672C\u5730\u4ED3\u5E93\uFF09\u3002\u6700\u540E <code>git push origin main</code> \u5373\u53EF\u63A8\u9001\u5230 GitHub\u3002</p><p>vscode \u56FE\u5F62\u754C\u9762\u5DF2\u7ECF\u96C6\u6210\u4E86 git \u7684\u4E00\u4E9B\u57FA\u672C\u64CD\u4F5C\uFF0C\u53EF\u4EE5\u5F88\u65B9\u4FBF\u7684\u5B8C\u6210\u63A8\u9001\u3002</p><p>\u5982\u679C\u60F3\u67E5\u770B\u6BCF\u6B21 commit \u9020\u6210\u7684\u66F4\u6539\uFF0C\u53EF\u4EE5\u4F7F\u7528 <code>git log</code>\uFF0C\u589E\u52A0\u53C2\u6570 <code>-p</code> \u4F1A\u663E\u793A\u6BCF\u6B21 commit \u9020\u6210\u7684\u53D8\u5316\uFF08\u589E\u91CF\u5F62\u5F0F\uFF09\uFF0C\u589E\u52A0\u53C2\u6570 <code>-num</code>\uFF08num \u662F\u81EA\u5DF1\u5236\u5B9A\u7684\u6570\u5B57\uFF09\uFF0C\u5219\u53EF\u4EE5\u9650\u5236\u663E\u793A\u7684\u63D0\u4EA4\u6B21\u6570\u3002</p>`,32),e=[o],r={setup(c,{expose:n}){return n({frontmatter:{}}),(i,l)=>(s(),a("div",p,e))}};export{r as default};
